/* ─── parser/parser-v1-points.js ─── */
/**
 * NCZ v1 Parser — Nokta + Text Modülü  (v3.0.0)
 * ══════════════════════════════════════════════════════════════════════
 *
 * ── NCZ BINARY FORMAT (DOĞRULANMIŞ) ───────────────────────────────────
 *
 * Kaynak: ncz_pure.py + ncz_native.c tersine mühendislik analizi
 *         (Jeomatik NCZ Reader — Erdinç Örsan Ünal)
 *
 * ── BLOK YAPISI ───────────────────────────────────────────────────────
 *
 *   [pos+0]     1 byte   → block_type  (21=0x15 temel, 22=0x16 GIS)
 *   [pos+1..4]  4 byte   → uint32 LE  → payload_size
 *   [pos+5]     1 byte   → (çeşitli, atlanır)
 *   [pos+6]     1 byte   → geometry_type
 *   [pos+7]     1 byte   → layer_code
 *   [pos+8..15] 8 byte   → double LE  → raw_x (Northing)
 *   [pos+16..23]8 byte   → double LE  → raw_y (Easting)
 *   [pos+24..27]4 byte   → float LE   → z
 *   [pos+28..31]4 byte   → float LE   → z_alt (z=0 ise bu kullanılır)
 *   [pos+37]    1 byte   → color_code
 *
 *   block_size  = uint32(pos+1) + 4
 *   total_size  = block_size + 1   → cursor bu kadar ilerler
 *
 *   gis_difference:
 *     block_type=21 → gd=0
 *     block_type=22 → gd=28  (tüm tip-özel offsetler 28 byte ileriden başlar)
 *
 * ── KOORDİNAT SWAP (KRİTİK) ───────────────────────────────────────────
 *
 *   NCZ binary'de:  raw_x = Northing (Y),  raw_y = Easting (X)
 *   Haritada:       coord.x = raw_y (Easting),  coord.y = raw_x (Northing)
 *
 * ── GEOMETRİ TİPLERİ ──────────────────────────────────────────────────
 *
 *   GT=1  : Nokta (Point)             ✅ Doğrulanmış
 *   GT=2  : Düz Çizgi (Line)          ✅ Doğrulanmış (lines.js)
 *   GT=3  : Daire (Circle)            ✅ Doğrulanmış (circle.js)
 *   GT=4  : Ark (Arc)                 ✅ Doğrulanmış
 *   GT=5  : Yazı (Text)               ✅ Doğrulanmış (gd'ye göre offset)
 *   GT=6  : Sembol (Symbol)           ✅ Doğrulanmış
 *   GT=7  : Polyline / Polygon        ✅ Doğrulanmış (lines.js)
 *   GT=9  : Compressed Curve          ✅ Doğrulanmış
 *   GT=10 : Döndürülmüş Kutu (Box)    ✅ Doğrulanmış (lines.js)
 *   GT=12 : Üçgen (Triangle)          ✅ Doğrulanmış
 *   GT=13 : Blok Referansı            ✅ Doğrulanmış
 *
 * ── GT=1 NOKTA LAYOUT (pos'tan itibaren) ──────────────────────────────
 *
 *   pos+7            : layer_code (1 byte)
 *   pos+8            : raw_x / Northing (float64)
 *   pos+16           : raw_y / Easting  (float64)
 *   pos+24           : z (float32)
 *   pos+28           : z_alt (float32, z=0 ise kullanılır)
 *   pos+37           : color_code (1 byte)
 *   pos+gd+86        : name_length (1 byte)
 *   pos+gd+87        : name string (Turkish encoded)
 *
 * ── GT=5 TEXT LAYOUT (pos'tan itibaren) ───────────────────────────────
 *
 *   pos+7            : layer_code (1 byte)
 *   pos+8            : raw_x / Northing (float64)
 *   pos+16           : raw_y / Easting  (float64)
 *   pos+24           : z (float32)
 *   pos+28           : z_alt (float32, z=0 ise kullanılır)
 *   pos+gd+86        : text_height (float32, >0 olmak zorunda)
 *   pos+gd+90        : rotation (float32, radyan → dereceye çevir)
 *   pos+gd+97        : text_length (1 byte)   ← birincil okuma noktası
 *   pos+gd+98        : text string (Turkish encoded)
 *
 *   Fallback sırası (Python parseri ile aynı):
 *     1) pos+gd+97 / pos+gd+98
 *     2) pos+gd+86 / pos+gd+87  (height alanını text gibi dene)
 *     3) pos+97    / pos+98      (gd=0 kabul et)
 *     4) pos+86    / pos+87
 *
 * ── GT=4 ARK LAYOUT ───────────────────────────────────────────────────
 *
 *   pos+8            : raw_x / merkez Northing (float64)
 *   pos+16           : raw_y / merkez Easting  (float64)
 *   pos+24           : z (float32)
 *   pos+gd+86        : radius (float64)
 *   pos+gd+104       : start_angle (float64, radyan veya derece)
 *   pos+gd+112       : end_angle   (float64, radyan veya derece)
 *
 *   Açı normalleştirme: |açı| <= 2π+0.001 → radyan, degrees() uygula
 *
 * ══════════════════════════════════════════════════════════════════════
 */

(function () {
  'use strict';

  // ══════════════════════════════════════════════════════════════════
  // FORMAT TANIMLARI
  // ══════════════════════════════════════════════════════════════════
  //
  // v3.0'da FORMAT_CONFIGS artık sadece sürüm etiketi ve katman tablosu
  // için kullanılıyor. Geometri offsetleri artık referansa göre
  // doğrudan pos'tan hesaplandığı için config'e gerek kalmadı.
  //
  // Durum  (✅=dosya ile doğrulandı  ⏳=dosya bekleniyor  ⚠️=tahminî)
  //
  //   FORMAT_V80 → ✅ Netcad 8.0.x.x  (referans)
  //   FORMAT_V85 → ⏳ Netcad 8.5.x.x  (V80 fallback)
  //   FORMAT_V77 → ⏳ Netcad 7.7.x.x  (V80 fallback)
  //   FORMAT_V76 → ⏳ Netcad 7.6.x.x  (V80 fallback)
  //   FORMAT_V70 → ⚠️ Netcad 7.0.x.x  (tahminî — doğrula)
  //   FORMAT_V52 → ⚠️ Netcad 5.2.x.x  (eski format — doğrula)

  const FORMAT_CONFIGS = {

    FORMAT_V80: {
      label: 'Netcad 8.0',
      layerTable: {
        entrySize:         29,
        nameOffset:         5,   // item_offset + 5 → katman adı (referans: item_offset+4=len, +5=string)
        nameLenOffset:      4,   // item_offset + 4 → isim uzunluğu
        invalidStreakLimit: 3,
      },
    },

    FORMAT_V85: {
      label: 'Netcad 8.5',
      _useBase: 'FORMAT_V80',
      layerTable: null,
    },

    FORMAT_V77: {
      label: 'Netcad 7.7',
      _useBase: 'FORMAT_V80',
      layerTable: null,
    },

    FORMAT_V76: {
      label: 'Netcad 7.6',
      _useBase: 'FORMAT_V80',
      layerTable: null,
    },

    FORMAT_V70: {
      label: 'Netcad 7.0',
      _useBase: 'FORMAT_V80',
      layerTable: {
        entrySize:         29,
        nameOffset:         5,
        nameLenOffset:      4,
        invalidStreakLimit: 5,   // Eski dosyalarda boş entry daha fazla
      },
    },

    FORMAT_V52: {
      label: 'Netcad 5.2',
      _useBase: 'FORMAT_V80',
      layerTable: null,   // TODO: entrySize farklı olabilir
    },
  };

  function resolveConfig(key) {
    const cfg = FORMAT_CONFIGS[key] || FORMAT_CONFIGS.FORMAT_V80;
    if (!cfg._useBase) return cfg;
    const base = resolveConfig(cfg._useBase);
    return {
      label:      cfg.label,
      layerTable: cfg.layerTable || base.layerTable,
    };
  }

  // ══════════════════════════════════════════════════════════════════
  // SÜRÜM TESPİTİ
  // ══════════════════════════════════════════════════════════════════
  //
  // NCZ'de versiyon bilgisi block_type=25 bloğunda binary olarak geçer.
  // Buna ek olarak dosyanın ilk 2000 byte'ında düz metin sürüm dizisi
  // de bulunabilir (bazı sürümler).
  //
  // Strateji:
  //   1) block_type=25 bloğunu tara → Turkish string oku
  //   2) Bulamazsan latin1 decode edip regex dene
  //   3) Hâlâ bulamazsan → FORMAT_V80 fallback

  function detectVersion(buf) {
    const a = new Uint8Array(buf);

    // Yöntem 1: block_type=25 bloğunu tara (referans: offset+5=len, offset+6=string)
    let pos = 0;
    while (pos + 10 < a.length) {
      const blockType = a[pos];
      const blockSize = (a[pos+1] | a[pos+2]<<8 | a[pos+3]<<16 | a[pos+4]<<24) + 4;
      const totalSize = blockSize + 1;

      if (blockSize < 4 || pos + totalSize > a.length) { pos++; continue; }

      if (blockType === 25) {
        const nameLen = a[pos + 5];
        if (nameLen > 0 && nameLen < 64 && pos + 6 + nameLen <= a.length) {
          const vStr = readTurkishStr(a, pos + 6, nameLen);
          if (vStr.length > 0) {
            const formatKey = versionStringToFormatKey(vStr);
            console.log(`[parser] block_type=25 sürüm: "${vStr}" → ${FORMAT_CONFIGS[formatKey].label}`);
            return { versionStr: vStr, formatKey };
          }
        }
      }

      pos += totalSize;
    }

    // Yöntem 2: Ham metin tarama
    const header = new TextDecoder('latin1').decode(new Uint8Array(buf, 0, Math.min(2000, buf.byteLength)));
    const m = header.match(/(\d+)\.(\d+)\.(\d+)\.(\d+)/);
    if (m) {
      const vStr = m[0];
      const formatKey = versionStringToFormatKey(vStr);
      console.log(`[parser] regex sürüm: "${vStr}" → ${FORMAT_CONFIGS[formatKey].label}`);
      return { versionStr: vStr, formatKey };
    }

    console.warn('[parser] Sürüm bulunamadı → FORMAT_V80 (fallback)');
    return { versionStr: 'unknown', formatKey: 'FORMAT_V80' };
  }

  function versionStringToFormatKey(vStr) {
    const m = vStr.match(/(\d+)\.(\d+)/);
    if (!m) return 'FORMAT_V80';
    const major = parseInt(m[1]);
    const minor = parseInt(m[2]);

    if      (major === 5 && minor === 2) return 'FORMAT_V52';
    else if (major === 7 && minor === 0) return 'FORMAT_V70';
    else if (major === 7 && minor === 6) return 'FORMAT_V76';
    else if (major === 7 && minor === 7) return 'FORMAT_V77';
    else if (major === 7)               return 'FORMAT_V77';
    else if (major === 8 && minor === 0) return 'FORMAT_V80';
    else if (major === 8 && minor >= 5)  return 'FORMAT_V85';
    else if (major >= 8)                 return 'FORMAT_V80';
    else if (major < 7)                  return 'FORMAT_V52';
    else                                 return 'FORMAT_V80';
  }

  // ══════════════════════════════════════════════════════════════════
  // TÜRKÇE KARAKTERLERİ
  // ══════════════════════════════════════════════════════════════════
  //
  // NCZ'nin kendi özel encoding tablosu — ne UTF-8 ne standart Latin-1.
  // Sadece bu 6 kod özel, geri kalanlar Latin-1 (chr(value)).

  const TR_MAP = {
    208: 'Ğ', 221: 'İ', 222: 'Ş',
    240: 'ğ', 253: 'ı', 254: 'ş',
  };

  function readTurkishStr(a, offset, length) {
    let s = '';
    const end = Math.min(offset + length, a.length);
    for (let i = offset; i < end; i++) {
      const c = a[i];
      if (c === 0) break;
      if (TR_MAP[c]) {
        s += TR_MAP[c];
      } else {
        s += String.fromCharCode(c);
      }
    }
    return s.trimEnd().replace(/\0+$/, '');
  }

  // ══════════════════════════════════════════════════════════════════
  // KATMAN TABLOSU
  // ══════════════════════════════════════════════════════════════════
  //
  // Referans: block_type=6 bloğu
  //   [offset+16..17] uint16 LE → katman sayısı
  //   Döngü, her katman 29 byte:
  //     item_offset = offset + 18 + (index * 29)
  //     item_offset+4 → isim uzunluğu (1 byte)
  //     item_offset+5 → katman adı (Turkish string)
  //
  // Fallback: eski tarz tarama (block_type=6 bulunamazsa)

  function readLayerTable(buf, ltCfg) {
    const a = new Uint8Array(buf);
    const lt = {};

    // Birincil yöntem: block_type=6 bloğunu referans formata göre oku
    let pos = 0;
    let found = false;
    while (pos + 20 < a.length) {
      const blockType = a[pos];
      const blockSize = (a[pos+1] | a[pos+2]<<8 | a[pos+3]<<16 | a[pos+4]<<24) + 4;
      const totalSize = blockSize + 1;

      if (blockSize < 4 || pos + totalSize > a.length) { pos++; continue; }

      if (blockType === 6) {
        const layerCount = a[pos+16] | (a[pos+17] << 8);
        let streak = 0;
        for (let i = 0; i < layerCount; i++) {
          const itemOffset = pos + 18 + (i * 29);
          if (itemOffset + 29 > a.length) break;
          const nameLen = a[itemOffset + 4];
          if (nameLen === 0 || nameLen > 40) {
            if (++streak >= ltCfg.invalidStreakLimit) break;
            continue;
          }
          const name = readTurkishStr(a, itemOffset + 5, nameLen);
          if (name.length >= 1) {
            lt[i] = name;
            streak = 0;
            found = true;
          }
        }
        if (found) {
          console.log(`[parser] block_type=6 katman tablosu: ${Object.keys(lt).length} katman`);
          return lt;
        }
      }

      pos += totalSize;
    }

    // Fallback: LEX.ST2 isimli blok (block_type=28, name="LEX.ST2") → renkleri de içerir
    // Burada sadece isimlere odaklanıyoruz
    pos = 0;
    while (pos + 30 < a.length) {
      const blockType = a[pos];
      const blockSize = (a[pos+1] | a[pos+2]<<8 | a[pos+3]<<16 | a[pos+4]<<24) + 4;
      const totalSize = blockSize + 1;

      if (blockSize < 4 || pos + totalSize > a.length) { pos++; continue; }

      if (blockType === 28) {
        const nameLen = a[pos + 5];
        if (nameLen > 0 && nameLen < 32) {
          const blockName = readTurkishStr(a, pos + 6, nameLen);
          if (blockName === 'LEX.ST2') {
            const layerCount = a[pos + 20];
            for (let i = 0; i < layerCount; i++) {
              // LEX.ST2: her katman 256 byte, katman adı erken offsette
              // Renk: item_offset + 56 (R,G,B)
              // İsim ayrıca block_type=6'dan okunmalı; burada placeholder
              lt[i] = lt[i] || `LC_${i}`;
            }
            console.log(`[parser] LEX.ST2 fallback: ${layerCount} katman rengi`);
            break;
          }
        }
      }

      pos += totalSize;
    }

    if (Object.keys(lt).length > 0) return lt;

    // Son çare: eski stride tarama
    console.warn('[parser] block_type=6 bulunamadı, stride tarama deneniyor');
    return readLayerTableLegacy(a, ltCfg);
  }

  function readLayerTableLegacy(a, ltCfg) {
    const lt = {};
    const ENTRY    = ltCfg.entrySize;
    const NAME_OFF = ltCfg.nameOffset;
    const NL_OFF   = ltCfg.nameLenOffset;
    const MAX_ST   = ltCfg.invalidStreakLimit;

    // Marker tarama: 0xfc veya 0xfd işaretli girişler
    const MARKERS = [0xfc, 0xfd];
    let earliest = -1;
    for (const marker of MARKERS) {
      for (let i = 0; i < a.length - ENTRY * 2; i++) {
        if (a[i + 4] !== marker || a[i + 4 + ENTRY] !== marker) continue;
        const nl = a[i + NL_OFF];
        if (nl < 1 || nl > 40) continue;
        let ok = true;
        for (let k = 0; k < nl; k++) {
          if (a[i + NAME_OFF + k] < 32 || a[i + NAME_OFF + k] > 254) { ok = false; break; }
        }
        if (ok && (earliest < 0 || i < earliest)) { earliest = i; break; }
      }
    }

    if (earliest >= 0) {
      let streak = 0;
      for (let lc = 0; lc < 400; lc++) {
        const p = earliest + lc * ENTRY;
        if (p + 9 >= a.length) break;
        const nl = a[p + NL_OFF];
        if (nl === 0) continue;
        if (nl > 40) { if (++streak >= MAX_ST) break; continue; }
        let ok = true;
        for (let k = 0; k < nl; k++) {
          if (a[p + NAME_OFF + k] < 32 || a[p + NAME_OFF + k] > 254) { ok = false; break; }
        }
        if (!ok) { if (++streak >= MAX_ST) break; continue; }
        streak = 0;
        const name = readTurkishStr(a, p + NAME_OFF, nl);
        if (name.length >= 1) lt[lc] = name;
      }
      if (Object.keys(lt).length > 0) return lt;
    }

    return lt;
  }

  function getLayerName(lt, layerCode) {
    // Referans: 0-tabanlı önce dene, sonra 1-tabanlı
    if (lt[layerCode] !== undefined) return lt[layerCode];
    if (layerCode > 0 && lt[layerCode - 1] !== undefined) return lt[layerCode - 1];
    return `LC_${layerCode}`;
  }

  // ══════════════════════════════════════════════════════════════════
  // KOORDİNAT YARDIMCILARI
  // ══════════════════════════════════════════════════════════════════

  // Türkiye UTM koordinat geçerlilik kontrolü
  // Northing: 3_000_000 – 6_000_000
  // Easting:  100_000   – 900_000
  function isValidUTM(northing, easting) {
    return (
      Number.isFinite(northing) && Number.isFinite(easting) &&
      northing > 3_000_000 && northing < 6_000_000 &&
      easting  >   100_000 && easting  <   900_000
    );
  }

  // Z okuma: z=0 ise z_alt'a bak (referans davranışı)
  function readZ(v, pos) {
    const z = v.getFloat32(pos + 24, true);
    if (z !== 0) return z;
    return v.getFloat32(pos + 28, true);
  }

  // ══════════════════════════════════════════════════════════════════
  // BLOK HEADER
  // ══════════════════════════════════════════════════════════════════
  //
  // Referans:
  //   block_type = a[pos]         (21=temel, 22=GIS)
  //   block_size = uint32LE(pos+1) + 4
  //   total_size = block_size + 1
  //   geometry_type = a[pos+6]
  //
  // Geçerli geometri bloğu kontrolü: block_type 21 veya 22, block_size >= 7

  function readBlockSize(a, pos) {
    return (a[pos+1] | a[pos+2]<<8 | a[pos+3]<<16 | a[pos+4]<<24) + 4;
  }

  function isGeomBlock(a, pos) {
    const bt = a[pos];
    return bt === 21 || bt === 22;
  }

  function gisOffset(a, pos) {
    // block_type=22 → gis_difference=28, block_type=21 → 0
    return a[pos] === 22 ? 28 : 0;
  }

  // ══════════════════════════════════════════════════════════════════
  // GT=1 NOKTA PARSER
  // ══════════════════════════════════════════════════════════════════

  function parsePoint(v, a, pos, gd, lt) {
    const lc = a[pos + 7];
    const nx = v.getFloat64(pos + 8,  true);   // raw_x = Northing
    const ey = v.getFloat64(pos + 16, true);   // raw_y = Easting
    if (!isValidUTM(nx, ey)) return null;

    const z  = readZ(v, pos);

    // İsim: length-prefixed string, pos+gd+86 = uzunluk, pos+gd+87 = string
    const nameLenOff = pos + gd + 86;
    let name = '';
    if (nameLenOff < a.length) {
      const nameLen = a[nameLenOff];
      if (nameLen > 0 && nameLen <= 64 && nameLenOff + 1 + nameLen <= a.length) {
        name = readTurkishStr(a, nameLenOff + 1, nameLen);
      }
    }

    return {
      gt:        1,
      lc,
      layerName: getLayerName(lt, lc),
      x:         ey,   // Easting → harita X
      y:         nx,   // Northing → harita Y
      z,
      name,
      isText:    false,
    };
  }

  // ══════════════════════════════════════════════════════════════════
  // GT=5 TEXT PARSER
  // ══════════════════════════════════════════════════════════════════
  //
  // Referans layout (pos'tan, gd=gis_difference):
  //   pos+gd+86  → text_height (float32, pozitif)
  //   pos+gd+90  → rotation   (float32, radyan)
  //   pos+gd+97  → text_length (1 byte)   ← birincil
  //   pos+gd+98  → text string
  //
  // Fallback sırası (Python parseri ile birebir):
  //   1) gd+97 / gd+98
  //   2) gd+86 / gd+87
  //   3) +97   / +98   (gd=0 varsay)
  //   4) +86   / +87

  function readTextPayload(a, pos, gd) {
    const candidates = [
      [pos + gd + 97, pos + gd + 98],
      [pos + gd + 86, pos + gd + 87],
      [pos + 97,      pos + 98],
      [pos + 86,      pos + 87],
    ];
    for (const [lenOff, strOff] of candidates) {
      if (lenOff < 0 || lenOff >= a.length) continue;
      const tLen = a[lenOff];
      if (tLen <= 0 || tLen > 240 || strOff + tLen > a.length) continue;
      const s = readTurkishStr(a, strOff, tLen).replace(/\0/g, '').trim();
      if (s.length > 0) return s;
    }
    return null;
  }

  function tryReadPositiveFloat(v, off, bufLen) {
    if (off < 0 || off + 4 > bufLen) return null;
    const val = v.getFloat32(off, true);
    if (!Number.isFinite(val) || val <= 0 || val > 100000) return null;
    return val;
  }

  function parseText(v, a, pos, gd, lt) {
    const lc = a[pos + 7];
    const nx = v.getFloat64(pos + 8,  true);
    const ey = v.getFloat64(pos + 16, true);
    if (!isValidUTM(nx, ey)) return null;

    const z = readZ(v, pos);

    const text = readTextPayload(a, pos, gd);
    if (!text) return null;

    // text_height: gd+86 önce, fallback +86
    let textHeight = tryReadPositiveFloat(v, pos + gd + 86, a.length);
    if (textHeight === null) textHeight = tryReadPositiveFloat(v, pos + 86, a.length);
    if (textHeight === null) return null;

    // rotation: gd+90 → radyan → derece
    let rotation = 0;
    const rotOff = pos + gd + 90;
    if (rotOff + 4 <= a.length) {
      rotation = (v.getFloat32(rotOff, true) * (180 / Math.PI)) % 360;
    }

    return {
      gt:         5,
      lc,
      layerName:  getLayerName(lt, lc),
      x:          ey,
      y:          nx,
      z,
      textHeight,
      angleDeg:   rotation,
      angleRad:   rotation * (Math.PI / 180),
      name:       text,
      isText:     true,
    };
  }

  // ══════════════════════════════════════════════════════════════════
  // GT=6 SEMBOL PARSER
  // ══════════════════════════════════════════════════════════════════
  //
  //   pos+gd+86  → sembol boyutu (float32)
  //   pos+gd+90  → rotation (float32, radyan)
  //   pos+gd+94  → symbol_code (1 byte)

  function parseSymbol(v, a, pos, gd, lt) {
    const lc = a[pos + 7];
    const nx = v.getFloat64(pos + 8,  true);
    const ey = v.getFloat64(pos + 16, true);
    if (!isValidUTM(nx, ey)) return null;

    const z = readZ(v, pos);

    let symbolSize = tryReadPositiveFloat(v, pos + gd + 86, a.length);
    if (symbolSize === null) symbolSize = tryReadPositiveFloat(v, pos + 86, a.length);
    if (symbolSize === null) symbolSize = 5.0;

    const symCodeOff = pos + gd + 94;
    const symbolCode = (symCodeOff < a.length) ? a[symCodeOff] : 0;

    let rotation = 0;
    const rotOff = pos + gd + 90;
    if (rotOff + 4 <= a.length) {
      rotation = (v.getFloat32(rotOff, true) * (180 / Math.PI)) % 360;
    }

    return {
      gt:         6,
      lc,
      layerName:  getLayerName(lt, lc),
      x:          ey,
      y:          nx,
      z,
      textHeight: symbolSize,
      angleDeg:   rotation,
      name:       `S${symbolCode}`,
      isText:     false,
    };
  }

  // ══════════════════════════════════════════════════════════════════
  // GT=4 ARK PARSER
  // ══════════════════════════════════════════════════════════════════
  //
  // Referans:
  //   pos+8      → raw_x / merkez Northing (float64)
  //   pos+16     → raw_y / merkez Easting  (float64)
  //   pos+24     → z (float32)
  //   pos+gd+86  → radius (float64)
  //   pos+gd+104 → start_angle (float64, radyan veya derece)
  //   pos+gd+112 → end_angle   (float64, radyan veya derece)
  //
  // Açı normalleştirme: |açı| <= 2π+0.001 → radyan kabul et, dereceye çevir

  function parseArc(v, a, pos, gd, lt) {
    const lc = a[pos + 7];
    const nx = v.getFloat64(pos + 8,  true);
    const ey = v.getFloat64(pos + 16, true);
    if (!isValidUTM(nx, ey)) return null;

    const z      = readZ(v, pos);
    const radius = v.getFloat64(pos + gd + 86,  true);
    let startA   = v.getFloat64(pos + gd + 104, true);
    let endA     = v.getFloat64(pos + gd + 112, true);

    if (!Number.isFinite(radius) || radius <= 0) return null;
    if (!Number.isFinite(startA) || !Number.isFinite(endA)) return null;

    // Radyan mı derece mi?
    const PI2 = 2 * Math.PI + 0.001;
    if (Math.abs(startA) <= PI2 && Math.abs(endA) <= PI2) {
      startA = startA * (180 / Math.PI);
      endA   = endA   * (180 / Math.PI);
    }

    return {
      gt:        4,
      lc,
      layerName: getLayerName(lt, lc),
      x:         ey,
      y:         nx,
      z,
      radius,
      startAngleDeg: startA,
      endAngleDeg:   endA,
      isText:    false,
    };
  }

  // ══════════════════════════════════════════════════════════════════
  // GÖMÜLÜ KONTEYNER TARAMASI
  // ══════════════════════════════════════════════════════════════════
  //
  // Referans: block_type 0,5,14,48,108,111,132,150,180 → içinde
  // type 21/22 geometri blokları gömülü.
  //
  // Sağlama: data[cursor+5] === data[cursor+6]  (referans koşulu)

  const EMBEDDED_CONTAINER_TYPES = new Set([0, 5, 14, 48, 108, 111, 132, 150, 180]);

  function scanEmbeddedContainer(v, a, containerPos, containerBlockSize, lt, out) {
    const start = containerPos + 5;
    const end   = containerPos + containerBlockSize;
    let cursor  = start;

    while (cursor + 6 < end) {
      const bt = a[cursor];
      if (bt !== 21 && bt !== 22) { cursor++; continue; }
      // Sağlama: a[cursor+5] === a[cursor+6]
      if (a[cursor + 5] !== a[cursor + 6]) { cursor++; continue; }

      const innerSize  = (a[cursor+1] | a[cursor+2]<<8 | a[cursor+3]<<16 | a[cursor+4]<<24) + 4;
      const innerTotal = innerSize + 1;
      if (innerSize < 7 || cursor + innerTotal > end) { cursor++; continue; }

      const igd = bt === 22 ? 28 : 0;
      const gt  = a[cursor + 6];
      parseGeomEntry(v, a, cursor, innerSize, igd, gt, lt, out);
      cursor += innerTotal;
    }
  }

  // ══════════════════════════════════════════════════════════════════
  // TEK GEOMETRİ ENTRY DISPATCH
  // ══════════════════════════════════════════════════════════════════

  function parseGeomEntry(v, a, pos, blockSize, gd, gt, lt, out) {
    // Bu modül GT=1 (nokta) ve GT=5 (yazı) ile GT=6 (sembol) ve GT=4 (ark) parse eder.
    // GT=2,3,7,9,10,12,13 → lines.js / circle.js tarafından işlenir.
    let result = null;
    if      (gt === 1) result = parsePoint (v, a, pos, gd, lt);
    else if (gt === 5) result = parseText  (v, a, pos, gd, lt);
    else if (gt === 6) result = parseSymbol(v, a, pos, gd, lt);
    else if (gt === 4) result = parseArc   (v, a, pos, gd, lt);
    if (result) out.push(result);
  }

  // ══════════════════════════════════════════════════════════════════
  // ANA PARSE FONKSİYONU
  // ══════════════════════════════════════════════════════════════════

  function parsePoints(buf) {
    if (window.NCZViewer && NCZViewer.ui && NCZViewer.ui.progress) {
      NCZViewer.ui.progress.setStage('read',  true);
      NCZViewer.ui.progress.setStage('ver',   false);
    }

    const { versionStr, formatKey } = detectVersion(buf);

    if (window.NCZViewer && NCZViewer.ui && NCZViewer.ui.progress) {
      NCZViewer.ui.progress.setStage('ver',   true, versionStr);
      NCZViewer.ui.progress.setStage('layer', false);
    }

    const fmt = resolveConfig(formatKey);
    const lt  = readLayerTable(buf, fmt.layerTable);

    if (window.NCZViewer && NCZViewer.ui && NCZViewer.ui.progress) {
      const lcnt = Object.keys(lt).length;
      NCZViewer.ui.progress.setStage('layer', true, lcnt + ' katman');
      NCZViewer.ui.progress.updateStats(undefined, lcnt);
      NCZViewer.ui.progress.setStage('parse', false, 'Noktalar okunuyor...');
    }

    console.log(`[parser-v1-points] ${fmt.label} (${versionStr}) | ${Object.keys(lt).length} katman`);

    const v      = new DataView(buf);
    const a      = new Uint8Array(buf);
    const points = [];
    let   pos    = 0;

    while (pos + 5 < buf.byteLength) {
      const bt        = a[pos];
      const blockSize = readBlockSize(a, pos);
      const totalSize = blockSize + 1;

      // Geçersiz blok → 1 byte atla
      if (blockSize < 4 || pos + totalSize > buf.byteLength) { pos++; continue; }

      if (bt === 21 || bt === 22) {
        // Doğrudan geometri bloğu
        if (blockSize >= 7) {
          const gd = bt === 22 ? 28 : 0;
          const gt = a[pos + 6];
          parseGeomEntry(v, a, pos, blockSize, gd, gt, lt, points);
        }
        pos += totalSize;

      } else if (EMBEDDED_CONTAINER_TYPES.has(bt)) {
        // Gömülü geometri konteyneri
        scanEmbeddedContainer(v, a, pos, blockSize, lt, points);
        pos += totalSize;

      } else {
        // Meta blok veya bilinmeyen → atla
        pos += totalSize;
      }

      // İlerleme güncelleme
      if (window.NCZViewer && NCZViewer.ui && NCZViewer.ui.progress && points.length % 500 === 0) {
        NCZViewer.ui.progress.updateStats(points.length, undefined);
        NCZViewer.ui.progress.setPct(Math.min(30, (pos / buf.byteLength) * 30));
        NCZViewer.ui.progress.setStage('parse', false, points.length + ' geom');
      }
    }

    if (window.NCZViewer && NCZViewer.ui && NCZViewer.ui.progress) {
      NCZViewer.ui.progress.setStage('parse',  true, points.length + ' geom');
      NCZViewer.ui.progress.setStage('render', false, 'Noktalar ekleniyor...');
    }

    console.log(`[parser-v1-points] ${points.length} nokta/yazı/sembol/ark parse edildi`);
    return { points, layerTable: lt, versionStr, formatKey };
  }

  // ══════════════════════════════════════════════════════════════════
  // MODÜL KAYDI
  // ══════════════════════════════════════════════════════════════════

  NCZViewer.registerModule({
    name: 'parser-v1-points',

    init(api) {
      console.log('[parser-v1-points] v3.0.0 yüklendi — doğrulanmış NCZ binary format');
    },

    onFileLoaded({ buf, filename, epsg }) {
      NCZViewer.ui.loading(true);
      setTimeout(() => {
        try {
          const { points, layerTable, versionStr, formatKey } = parsePoints(buf);
          if (points.length === 0) {
            console.warn('[parser-v1-points] Nokta/yazı bulunamadı — event yine de yayınlanıyor');
          }
          const payload = { points, layerTable, epsg, filename, buf, versionStr, formatKey };
          NCZViewer.events.emit('ncz:v1:parsed', payload);
          NCZViewer.events.emit('v1:points:parsed', payload);
        } catch (err) {
          console.error('[parser-v1-points] Parse hatası:', err);
          NCZViewer.ui.toast('Parse hatası: ' + err.message, 'err', 5000);
          if (window.NCZViewer && NCZViewer.ui && NCZViewer.ui.progress) {
            NCZViewer.ui.progress.hide();
          }
        }
        NCZViewer.ui.loading(false);
      }, 50);
    },
  });

  // ══════════════════════════════════════════════════════════════════
  // DIŞA AÇILAN YARDIMCILAR
  // ══════════════════════════════════════════════════════════════════

  window.NCZParserV1 = {
    detectVersion,
    FORMAT_CONFIGS,
    resolveConfig,
    readLayerTable,
    readTurkishStr,
    isValidUTM,
    isGeomBlock,
    gisOffset,
    readBlockSize,
    parsePoints,
    parsePoint,
    parseText,
    parseSymbol,
    parseArc,
    EMBEDDED_CONTAINER_TYPES,
    SUPPORTED_VERSIONS: ['FORMAT_V52','FORMAT_V70','FORMAT_V76','FORMAT_V77','FORMAT_V80','FORMAT_V85'],
  };

})();


/* ─── render/points.js ─── */
/**
 * Points Renderer  v1.2
 * ─────────────────────
 * Düzeltmeler v1.2:
 *  - toWGS koordinat sırası düzeltildi:
 *    Parser point.x = Easting, point.y = Northing üretir.
 *    proj4'e [Easting, Northing] gitmeli → toWGS(x, y) = proj4([x, y])
 *    Eskisi: proj4([y, x]) = proj4([Northing, Easting]) → noktalar Hint Okyanusu'nda
 *    Yenisi: proj4([x, y]) = proj4([Easting, Northing]) → noktalar Türkiye'de ✅
 *
 * Düzeltmeler v1.1:
 *  - 🔍 Büyüteç → seçili nokta değil tüm katmana sığdır
 *  - 📋 Kopyala → "Y: xxx, X: yyy" UTM formatında
 *  - Popup → sadece Y / X UTM göster, Z sadece 0 değilse
 */

(function () {
  'use strict';

  // WGS84 dönüşümü
  // point.x = Easting, point.y = Northing (parser-v1-points.js sözleşmesi)
  // proj4('EPSG:xxxx', 'EPSG:4326', [Easting, Northing]) → [lon, lat]
  function toWGS(x, y, epsg) {
    try {
      const [lon, lat] = proj4('EPSG:' + epsg, 'EPSG:4326', [x, y]);
      return isFinite(lat) && isFinite(lon) ? { lat, lon } : null;
    } catch (e) { return null; }
  }

  // WGS84 → UTM
  function toUTM(lat, lon, epsg) {
    try {
      const [E, N] = proj4('EPSG:4326', 'EPSG:' + epsg, [lon, lat]);
      return isFinite(E) && isFinite(N) ? { E, N } : null;
    } catch (e) { return null; }
  }

  // Katman sınırları (zoom to layer için)
  const _bounds = {};

  // Popup HTML
  function makePopup(point, ll, epsg) {
    const utm = toUTM(ll.lat, ll.lng, epsg);
    const lc  = point.lc;
    const copyStr = utm
      ? `Y: ${utm.N.toFixed(3)}, X: ${utm.E.toFixed(3)} (EPSG:${epsg})`
      : `Lat: ${ll.lat.toFixed(6)}, Lon: ${ll.lng.toFixed(6)}`;

    const rows = [
      ['Katman',   point.layerName],
      ['Geometri', 'Nokta'],
    ];
    if (point.name) rows.push(['Metin', point.name]);
    if (utm) {
      rows.push(
        ['Y (Kuzey)', utm.N.toFixed(3)],
        ['X (Doğu)',  utm.E.toFixed(3)],
      );
    }
    if (point.z && Math.abs(point.z) > 0.001) {
      rows.push(['Z', point.z.toFixed(3)]);
    }

    const tbl = rows.map(r => `<tr><td>${r[0]}</td><td>${r[1]}</td></tr>`).join('');

    // copy metnini base64 ile encode et (özel karakterlerden kaçınmak için)
    const copyB64 = btoa(unescape(encodeURIComponent(copyStr)));

    return `<div>
      <div class="pop-hd">Öznitelikler</div>
      <table class="pop-tbl"><tbody>${tbl}</tbody></table>
      <div class="pop-actions">
        <button class="pop-btn" title="Tüm katmanı göster"
          onclick="NCZViewer._zoomToLayer(${lc})">🔍</button>
        <button class="pop-btn" title="Y/X kopyala"
          onclick="NCZViewer._copyB64(this,'${copyB64}')">📋</button>
        <button class="pop-btn" title="Katmanı gizle"
          onclick="NCZViewer.layers.setVisible(${lc},false);NCZViewer.ui.refreshLayerLists();NCZViewer.map.closePopup();">👁</button>
      </div>
    </div>`;
  }

// Nokta render (Z + Text destekli)
  function renderPoint(point, epsg, group, api) {
    // GT=4 ark merkez noktaları haritada gösterilmez
    // (ark geometrisi lines.js tarafından çizilir, merkez nokta gereksiz)
    if (point.gt === 4) return;

    const wgs = toWGS(point.x, point.y, epsg);
    if (!wgs) return;
    const { lat, lon } = wgs;
    const col = api.layers.color(point.lc);

    if (!_bounds[point.lc]) _bounds[point.lc] = [];
    _bounds[point.lc].push([lat, lon]);

    // ── gt=5 TEXT geometrisi ─────────────────────────────────
    if (point.isText) {
      const esc = (point.name || '').replace(/[<>&"]/g, ch =>
        ({ '<':'&lt;', '>':'&gt;', '&':'&amp;', '"':'&quot;' }[ch]));
      const rot = point.angleDeg ? `rotate(${(-point.angleDeg).toFixed(1)}deg)` : '';
      const fsize = Math.max(9, Math.min(16, (point.textHeight || 3) * 0.8));
      const marker = L.marker([lat, lon], {
        interactive: true,
        icon: L.divIcon({
          className: 'ncz-text-obj-icon',
          html: `<div class="ncz-text-obj" style="color:${col};transform:${rot};font-size:${fsize}px">${esc}</div>`,
          iconSize: [0, 0], iconAnchor: [0, 0],
        })
      });
      marker.on('click', () => {
        const ll = L.latLng(lat, lon);
        L.popup({ maxWidth: 280 }).setLatLng(ll).setContent(makePopup(point, ll, epsg)).openOn(api.map);
      });
      group.addLayer(marker);
      return;
    }

    // ── gt=1 NOKTA geometrisi ────────────────────────────────
    const marker = L.circleMarker([lat, lon], {
      radius: 4, color: col, fillColor: col,
      fillOpacity: 0.85, weight: 1.2, opacity: 0.9,
    });

    // --- ETİKET GÜNCELLEMESİ (Merkez Kapsayıcı) ---
    let labelHtml = '<div class="ncz-lbl-wrapper">';
    if (point.name) {
      labelHtml += `<div class="ncz-pname">${point.name}</div>`;
    }
    if (point.z !== undefined && Math.abs(point.z) > 0.0001) {
      labelHtml += `<div class="ncz-pz">${point.z.toFixed(2)}</div>`;
    }
    labelHtml += '</div>';

    if (point.name || (point.z !== undefined && Math.abs(point.z) > 0.0001)) {
      marker.bindTooltip(labelHtml, {
        permanent: true, 
        direction: 'center', // Etiketi noktanın tam ortasına koy
        className: 'ncz-lbl-transparent', // Leaflet'in varsayılan arkaplanını sil
        opacity: 1 
      });
    }
    // ----------------------------------------------

    marker.on('click', () => {
      const ll = L.latLng(lat, lon);
      L.popup({ maxWidth: 280 })
        .setLatLng(ll)
        .setContent(makePopup(point, ll, epsg))
        .openOn(api.map);
    });

    group.addLayer(marker);
  }

  // Global yardımcılar — popup onclick'ten çağrılır
  NCZViewer._zoomToLayer = function (lc) {
    const pts = _bounds[lc];
    if (!pts || pts.length === 0) return;
    NCZViewer.map.closePopup();
    pts.length === 1
      ? NCZViewer.map.setView(pts[0], 18, { animate: true })
      : NCZViewer.map.fitBounds(L.latLngBounds(pts).pad(0.1), { animate: true });
  };

  NCZViewer._copyB64 = function (btn, b64) {
    const text = decodeURIComponent(escape(atob(b64)));
    navigator.clipboard?.writeText(text).catch(() => {
      const ta = document.createElement('textarea');
      ta.value = text; document.body.appendChild(ta);
      ta.select(); document.execCommand('copy'); ta.remove();
    });
    const orig = btn.textContent;
    btn.textContent = '✓';
    setTimeout(() => btn.textContent = orig, 1500);
  };

  // Modül kaydı
  NCZViewer.registerModule({
    name: 'points-renderer',
    init(api) {
      console.log('[points-renderer] v1.2 yüklendi — GT=1 nokta + GT=5 yazı render');
      // Text nesneleri için CSS
      const style = document.createElement('style');
      style.innerHTML = `
        .ncz-text-obj-icon { overflow: visible; }
        .ncz-text-obj {
          white-space: nowrap;
          font-family: 'JetBrains Mono', monospace;
          font-weight: 600;
          line-height: 1;
          pointer-events: auto;
          text-shadow: 0 0 3px rgba(0,0,0,0.8), 0 0 6px rgba(0,0,0,0.6);
          transform-origin: left bottom;
        }
      `;
      document.head.appendChild(style);
    },
    onDataCleared() { Object.keys(_bounds).forEach(k => delete _bounds[k]); },
  });

  // Event dinleyici
  NCZViewer.events.on('v1:points:parsed', ({ points, layerTable, epsg, filename }) => {
    const api = NCZViewer;
    if (!points || points.length === 0) return;
    api.ui.loading(true);

    setTimeout(() => {
      try {
        Object.keys(_bounds).forEach(k => delete _bounds[k]);

        const byLC = {};
        for (const pt of points) (byLC[pt.lc] = byLC[pt.lc] || []).push(pt);

        let total = 0;
        for (const [lc, pts] of Object.entries(byLC)) {
          const lcInt = parseInt(lc);
          const name  = layerTable[lcInt] || `LC_${lcInt}`;
          const group = L.layerGroup().addTo(api.map);
          api.layers.register(lcInt, name, group);
          for (const pt of pts) renderPoint(pt, epsg, group, api);
          total += pts.length;
          console.log(`[points-renderer] ${name} (LC=${lcInt}): ${pts.length} nokta`);
        }

        api.ui.updateStats(
          total.toLocaleString('tr'),
          Object.keys(byLC).length,
          filename || '—',
          'EPSG:' + epsg,
        );
        api.ui.showLayerUI();
        api.ui.refreshLayerLists();

        const allPts = Object.values(_bounds).flat();
        if (allPts.length > 0) api.map.fitBounds(L.latLngBounds(allPts).pad(0.08));

        api.ui.toast(`✓ ${total.toLocaleString('tr')} nokta yüklendi`, 'ok', 2500);
        console.log(`[points-renderer] Toplam ${total} nokta`);
      } catch (err) {
        console.error('[points-renderer] Hata:', err);
        api.ui.toast('Render hatası: ' + err.message, 'err', 5000);
      }
      api.ui.loading(false);
    }, 30);
  });

})();


/* ─── render/lines.js ─── */
/**
 * NCZ v1 Lines Renderer  v3.0  ★ BLOK HEADER DÜZELTİLDİ
 * ══════════════════════════════════════════════════════════════════════
 *
 * Düzeltmeler v3.0:
 *  - Blok header: 4-byte uint32 LE (eskisi 2-byte → büyük dosyalarda yanlış)
 *  - Tip 22 (0x16) blok desteği eklendi + gis_difference (gd=28) uygulandı
 *  - base = pos+7 kayması kaldırıldı; tüm offsetler pos'tan
 *  - GT=2 Line:  pos+8/16/24 (N/E/Z), son nokta pos+blockSize-19/-11/-3
 *  - GT=4 Arc:   pos+gd+86 radius, pos+gd+104 startAngle, pos+gd+112 endAngle
 *  - GT=7 Poly:  pos+gd+113'ten koordinat dizisi
 *  - GT=10 Box:  pos+8/16 (N1/E1), pos+gd+104/112 (N2/E2), pos+gd+120 rotation
 *  - toWGS(N, E) → proj4([E, N]) tutarlı kaldı (lines zaten doğruydu)
 *
 * ── GT offsetleri (pos'tan, gd = gis_difference) ──────────────────────
 *
 *   GT=2 Line:
 *     pos+7            : layer_code
 *     pos+8            : N1 (float64)
 *     pos+16           : E1 (float64)
 *     pos+24           : Z1 (float32)
 *     pos+blockSize-19 : N2 (float64)
 *     pos+blockSize-11 : E2 (float64)
 *     pos+blockSize-3  : Z2 (float32)
 *
 *   GT=4 Arc:
 *     pos+7            : layer_code
 *     pos+8            : merkez N (float64)
 *     pos+16           : merkez E (float64)
 *     pos+24           : Z (float32)
 *     pos+gd+86        : radius (float64)
 *     pos+gd+104       : startAngle (float64, radyan)
 *     pos+gd+112       : endAngle   (float64, radyan)
 *
 *   GT=7 Polyline / Polygon:
 *     pos+7            : layer_code
 *     pos+gd+86        : label length (1 byte)
 *     pos+gd+87        : label string
 *     Vertex sayısı    : (blockSize + 1 - 113 - gd) / 24
 *     Vertex başlangıcı: pos + gd + 113
 *     Her vertex 24 byte: N(f64) + E(f64) + Z(f64)
 *
 *   GT=10 Box:
 *     pos+7            : layer_code
 *     pos+8            : N1 sol-alt (float64)
 *     pos+16           : E1 sol-alt (float64)
 *     pos+gd+104       : N2 karşı köşe (float64)
 *     pos+gd+112       : E2 karşı köşe (float64)
 *     pos+gd+120       : rotation (float32, radyan)
 *
 * ══════════════════════════════════════════════════════════════════════
 */

(function () {
  'use strict';

  // Türkçe karakter tablosu
  const TR = {
    253:'ı', 240:'ğ', 254:'ş', 221:'İ', 208:'Ğ', 222:'Ş',
    246:'ö', 214:'Ö', 252:'ü', 220:'Ü', 231:'ç', 199:'Ç',
  };
  window._NCZ_TR = TR;

  // ── proj4 dönüşümü ─────────────────────────────────────────────────
  // lines.js içindeki coords dizisi [N, E] sırasında tutulur.
  // toWGS(N, E) → proj4([E, N]) → [lon, lat]  (bu doğru, değişmedi)
  function toWGS(n, e, epsg) {
    try {
      const [lon, lat] = proj4('EPSG:' + epsg, 'EPSG:4326', [e, n]);
      return isFinite(lat) && isFinite(lon) ? [lat, lon] : null;
    } catch (_) { return null; }
  }

  function isValidUTM(n, e) {
    return Number.isFinite(n) && Number.isFinite(e) &&
      n > 3_000_000 && n < 6_000_000 &&
      e >   100_000 && e <   900_000;
  }

  // ── Blok header yardımcıları ────────────────────────────────────────
  function readBlockSize(a, pos) {
    return (a[pos+1] | a[pos+2]<<8 | a[pos+3]<<16 | a[pos+4]<<24) + 4;
  }

  function gisOffset(a, pos) {
    return a[pos] === 22 ? 28 : 0;
  }

  function readTurkishStr(a, offset, length) {
    let s = '';
    const end = Math.min(offset + length, a.length);
    for (let i = offset; i < end; i++) {
      const c = a[i];
      if (c === 0) break;
      s += TR[c] ? TR[c] : String.fromCharCode(c);
    }
    return s.trimEnd();
  }

  function layerInfoFor(api, groups, lc, name) {
    if (!groups[lc]) {
      let layerInfo = api.layers.get(lc);
      if (!layerInfo) {
        const grp = L.layerGroup().addTo(api.map);
        layerInfo = api.layers.register(lc, name || `LC_${lc}`, grp);
      }
      groups[lc] = layerInfo;
    }
    return groups[lc];
  }

  // ── Ark interpolasyonu ─────────────────────────────────────────────
  // Netcad MATH konvansiyonu (görsel testlerle doğrulandı):
  //   0 rad = +Easting yönü, CCW pozitif
  //   dE = r·cos(rad), dN = r·sin(rad)
  function interpolateArc(nc, ec, r, startRad, endRad) {
    const G = 200 / Math.PI;
    const startG = startRad * G;
    const endG   = endRad   * G;

    let sweepG = ((endG - startG) % 400 + 400) % 400;
    if (sweepG < 0.0001) sweepG = 400;

    const sweepRad = sweepG * Math.PI / 200;
    const segments = Math.max(8, Math.min(128, Math.ceil(sweepG / 3)));

    const pts = [];
    for (let i = 0; i <= segments; i++) {
      const ang = startRad + sweepRad * (i / segments);
      pts.push([nc + r * Math.sin(ang), ec + r * Math.cos(ang)]);
    }
    return pts;
  }

  // ── GT=2 Line ──────────────────────────────────────────────────────
  function parseLine(v, a, pos, blockSize, lt) {
    const lc = a[pos + 7];
    const n1 = v.getFloat64(pos + 8,  true);
    const e1 = v.getFloat64(pos + 16, true);
    const z1 = v.getFloat32(pos + 24, true);
    if (!isValidUTM(n1, e1)) return null;

    const n2 = v.getFloat64(pos + blockSize - 19, true);
    const e2 = v.getFloat64(pos + blockSize - 11, true);
    const z2 = v.getFloat32(pos + blockSize - 3,  true);
    if (!isValidUTM(n2, e2)) return null;

    return {
      type: 'Çizgi', gt: 2, lc,
      layerName: lt[lc] || `LC_${lc}`,
      z1,
      coords: [[n1, e1], [n2, e2]],
    };
  }

  // ── GT=4 Arc ───────────────────────────────────────────────────────
  function parseArc(v, a, pos, gd, lt) {
    const lc = a[pos + 7];
    const nc = v.getFloat64(pos + 8,  true);
    const ec = v.getFloat64(pos + 16, true);
    if (!isValidUTM(nc, ec)) return null;

    const z        = v.getFloat32(pos + 24, true);
    const r        = v.getFloat64(pos + gd + 86,  true);
    let   startRad = v.getFloat64(pos + gd + 104, true);
    let   endRad   = v.getFloat64(pos + gd + 112, true);

    if (!Number.isFinite(r) || r < 0.0001 || r > 1e6) return null;
    if (!Number.isFinite(startRad) || !Number.isFinite(endRad)) return null;

    // Açı normalize: |açı| <= 2π+0.001 → radyan kabul et
    const PI2 = 2 * Math.PI + 0.001;
    if (Math.abs(startRad) <= PI2 && Math.abs(endRad) <= PI2) {
      // zaten radyan, interpolateArc doğrudan kullanır
    } else {
      // derece → radyan
      startRad = startRad * Math.PI / 180;
      endRad   = endRad   * Math.PI / 180;
    }

    const coords = interpolateArc(nc, ec, r, startRad, endRad);
    if (coords.length < 2) return null;

    const G      = 200 / Math.PI;
    const startG = startRad * G;
    const endG   = endRad   * G;
    const sweepG = ((endG - startG) % 400 + 400) % 400 || 400;
    const arcLen = r * (sweepG * Math.PI / 200);

    return {
      type: 'Ark', gt: 4, lc,
      layerName: lt[lc] || `LC_${lc}`,
      z1: z, coords, radius: r,
      centerN: nc, centerE: ec,
      startG, endG, sweepG, arcLength: arcLen,
    };
  }

  // ── GT=7 Polyline / Polygon ────────────────────────────────────────
  function parsePolyline(v, a, pos, blockSize, gd, lt) {
    const lc = a[pos + 7];

    const ptCount = Math.floor((blockSize + 1 - 113 - gd) / 24);
    if (ptCount < 2 || ptCount > 50000) return null;

    // Etiket (opsiyonel)
    let label = '';
    const lblLenOff = pos + gd + 86;
    if (lblLenOff < a.length) {
      const lblLen = a[lblLenOff];
      if (lblLen > 0 && lblLen <= 240) {
        label = readTurkishStr(a, lblLenOff + 1, lblLen);
      }
    }

    const coords = [];
    const startOff = pos + gd + 113;
    for (let i = 0; i < ptCount; i++) {
      const off = startOff + i * 24;
      if (off + 16 > pos + blockSize + 1) break;
      const n = v.getFloat64(off,     true);
      const e = v.getFloat64(off + 8, true);
      if (!isValidUTM(n, e)) continue;
      const last = coords[coords.length - 1];
      if (!last || Math.abs(last[0] - n) > 0.0005 || Math.abs(last[1] - e) > 0.0005) {
        coords.push([n, e]);
      }
    }
    if (coords.length < 2) return null;

    const first = coords[0];
    const last2 = coords[coords.length - 1];
    const isClosed = coords.length >= 3 &&
      Math.abs(first[0] - last2[0]) < 0.01 &&
      Math.abs(first[1] - last2[1]) < 0.01;

    return {
      type:      isClosed ? 'Kapalı Alan' : 'Polyline',
      gt:        7, lc,
      layerName: lt[lc] || `LC_${lc}`,
      coords, label, isClosed,
      isFilled:  isClosed,   // basit heuristic
      tarea:     0,
    };
  }

  // ── GT=10 Box ──────────────────────────────────────────────────────
  //
  // Referans: sol-alt köşe + karşı köşe + dönme açısı
  //   pos+8        : N1 sol-alt (float64)
  //   pos+16       : E1 sol-alt (float64)
  //   pos+gd+104   : N2 karşı köşe (float64)
  //   pos+gd+112   : E2 karşı köşe (float64)
  //   pos+gd+120   : rotation (float32, radyan)
  //
  // NetCAD açısı sol-alt köşeden yukarı çıkan kenara göre:
  //   side_x  =  sin(angle), side_y  =  cos(angle)
  //   bottom_x =  cos(angle), bottom_y = -sin(angle)
  function parseBox(v, a, pos, gd, lt) {
    const lc = a[pos + 7];
    const n1 = v.getFloat64(pos + 8,  true);
    const e1 = v.getFloat64(pos + 16, true);
    if (!isValidUTM(n1, e1)) return null;

    const n2  = v.getFloat64(pos + gd + 104, true);
    const e2  = v.getFloat64(pos + gd + 112, true);
    if (!isValidUTM(n2, e2)) return null;

    const rotRad = v.getFloat32(pos + gd + 120, true);
    const rotDeg = ((rotRad * 180 / Math.PI) % 360 + 360) % 360;
    const angle  = rotDeg * Math.PI / 180;

    const width  = Math.abs(e2 - e1);
    const height = Math.abs(n2 - n1);
    if (width < 0.001 || height < 0.001) return null;

    const sideX   =  Math.sin(angle);
    const sideY   =  Math.cos(angle);
    const bottomX =  Math.cos(angle);
    const bottomY = -Math.sin(angle);

    // 5 köşe (kapalı halka)
    const p0n = n1, p0e = e1;
    const p1n = p0n + bottomY * width,  p1e = p0e + bottomX * width;
    const p2n = p1n + sideY   * height, p2e = p1e + sideX   * height;
    const p3n = p0n + sideY   * height, p3e = p0e + sideX   * height;

    return {
      type:      'Dikdörtgen', gt: 10, lc,
      layerName: lt[lc] || `LC_${lc}`,
      coords:    [[p0n,p0e],[p1n,p1e],[p2n,p2e],[p3n,p3e],[p0n,p0e]],
      width, height, rotDeg,
      isClosed: true, isFilled: false,
    };
  }

  // ── En yakın vertex bulma ──────────────────────────────────────────
  // clickLatLng (WGS84) ile obj.coords (UTM [N,E][]) arasında
  // Euclidean mesafe karşılaştırması — proj4 dönüşümü olmadan piksel-yakın vertex
  function nearestVertex(coords, clickLatLng, epsg) {
    if (!coords || coords.length === 0) return null;
    let best = null, bestDist = Infinity;
    for (const [n, e] of coords) {
      // UTM → WGS84
      let wgsLat, wgsLon;
      try {
        [wgsLon, wgsLat] = proj4('EPSG:' + epsg, 'EPSG:4326', [e, n]);
      } catch (_) { continue; }
      if (!isFinite(wgsLat) || !isFinite(wgsLon)) continue;
      const dLat = wgsLat - clickLatLng.lat;
      const dLon = wgsLon - clickLatLng.lng;
      const d = dLat * dLat + dLon * dLon;
      if (d < bestDist) { bestDist = d; best = { N: n, E: e }; }
    }
    return best;
  }

  // ── Popup ──────────────────────────────────────────────────────────
  function makePopup(obj, epsg, clickLatLng) {
    // En yakın vertex'i bul (varsa), yoksa ilk koordinat
    const nearest = clickLatLng
      ? nearestVertex(obj.coords, clickLatLng, epsg)
      : null;
    const yVal = nearest ? nearest.N : (obj.coords ? obj.coords[0][0] : 0);
    const xVal = nearest ? nearest.E : (obj.coords ? obj.coords[0][1] : 0);

    const copyStr = `Y: ${yVal.toFixed(3)}, X: ${xVal.toFixed(3)} (EPSG:${epsg})`;
    const copyB64 = btoa(unescape(encodeURIComponent(copyStr)));

    const rows = [['Katman', obj.layerName], ['Geometri', obj.type]];

    if (obj.gt === 10) {
      rows.push(
        ['Genişlik',   `${obj.width.toFixed(3)} m`],
        ['Yükseklik',  `${obj.height.toFixed(3)} m`],
        ['Alan',       `${(obj.width * obj.height).toFixed(2)} m²`],
        ['Dönme',      `${obj.rotDeg.toFixed(2)}°`],
      );
    } else if (obj.gt === 7) {
      if (obj.label) rows.push(['Ad', obj.label]);
      rows.push(
        ['Kapalı', obj.isClosed ? 'Evet' : 'Hayır'],
        ['Vertex', String(obj.coords.length)],
      );
      if (obj.tarea && Math.abs(obj.tarea) > 0.001) {
        rows.push(['Alan', `${obj.tarea.toFixed(2)} m²`]);
      }
    } else if (obj.gt === 4) {
      rows.push(
        ['Merkez Y',   obj.centerN.toFixed(3)],
        ['Merkez X',   obj.centerE.toFixed(3)],
        ['Yarıçap',    `${obj.radius.toFixed(3)} m`],
        ['Baş. Açı',   `${obj.startG.toFixed(3)} g`],
        ['Bit. Açı',   `${obj.endG.toFixed(3)} g`],
        ['Yay Uzun.',  `${obj.arcLength.toFixed(3)} m`],
      );
    } else if (obj.gt === 2 && obj.len) {
      rows.push(['Uzunluk', `${obj.len.toFixed(2)} m`]);
    }

    // ── Koordinat satırları ───────────────────────────────────────────
    rows.push(
      ['', ''],  // ince ayraç
      ['Y (Kuzey)', yVal.toFixed(3)],
      ['X (Doğu)',  xVal.toFixed(3)],
    );

    const tbl = rows.map(r =>
      r[0] === ''
        ? `<tr><td colspan="2" style="border-top:1px solid var(--bd);padding:3px 0 0"></td></tr>`
        : `<tr><td>${r[0]}</td><td>${r[1]}</td></tr>`
    ).join('');

    return `<div>
      <div class="pop-hd">Öznitelikler</div>
      <table class="pop-tbl"><tbody>${tbl}</tbody></table>
      <div class="pop-actions">
        <button class="pop-btn" title="Tüm katmanı göster"
          onclick="NCZViewer._zoomToLayer(${obj.lc})">🔍</button>
        <button class="pop-btn" title="Y/X kopyala"
          onclick="NCZViewer._copyB64(this,'${copyB64}')">📋</button>
      </div>
    </div>`;
  }

  const _bounds = {};

  function renderObject(obj, epsg, api, groups) {
    const layerInfo = layerInfoFor(api, groups, obj.lc, obj.layerName);
    const col = layerInfo.color;

    if (!obj.coords || obj.coords.length < 2) return false;

    const latlngs = [];
    for (const [n, e] of obj.coords) {
      const ll = toWGS(n, e, epsg);
      if (ll) latlngs.push(ll);
    }
    if (latlngs.length < 2) return false;

    if (!_bounds[obj.lc]) _bounds[obj.lc] = [];
    _bounds[obj.lc].push(...latlngs);

    let shape;
    if ((obj.gt === 7 || obj.gt === 10) && obj.isClosed && latlngs.length >= 3) {
      shape = L.polygon(latlngs, {
        color: col, weight: 2, opacity: 0.9,
        fillColor: col,
        fillOpacity: obj.isFilled ? 0.18 : 0.06,
      });
    } else {
      shape = L.polyline(latlngs, { color: col, weight: 2, opacity: 0.88 });
    }

    shape.on('click', ev => {
      L.popup({ maxWidth: 300 })
        .setLatLng(ev.latlng)
        .setContent(makePopup(obj, epsg, ev.latlng))
        .openOn(api.map);
    });
    layerInfo.group.addLayer(shape);
    return true;
  }

  // ── Ana parse + render döngüsü ──────────────────────────────────────
  function parseAndRender(buf, epsg, api) {
    const v  = new DataView(buf);
    const a  = new Uint8Array(buf);

    let lt = {};
    if (window.NCZParserV1) {
      const { formatKey } = NCZParserV1.detectVersion(buf);
      const fmt = NCZParserV1.resolveConfig(formatKey);
      lt = NCZParserV1.readLayerTable(buf, fmt.layerTable);
    }

    const groups  = {};
    let rendered  = 0;
    let pos       = 0;

    while (pos + 5 < buf.byteLength) {
      const bt        = a[pos];
      const blockSize = readBlockSize(a, pos);
      const totalSize = blockSize + 1;

      if (blockSize < 4 || pos + totalSize > buf.byteLength) { pos++; continue; }

      if (bt === 21 || bt === 22) {
        if (blockSize >= 7) {
          const gd = bt === 22 ? 28 : 0;
          const gt = a[pos + 6];
          let obj  = null;
          try {
            if      (gt === 2)  obj = parseLine    (v, a, pos, blockSize, lt);
            else if (gt === 4)  obj = parseArc     (v, a, pos, gd, lt);
            else if (gt === 7)  obj = parsePolyline(v, a, pos, blockSize, gd, lt);
            else if (gt === 10) obj = parseBox     (v, a, pos, gd, lt);
          } catch (_) {}

          if (obj && renderObject(obj, epsg, api, groups)) {
            rendered++;
            if (api.ui?.progress && rendered % 200 === 0) {
              api.ui.progress.updateStats(api.ui.progress._geom + 200, undefined);
              api.ui.progress.setPct(30 + Math.min(50, (pos / buf.byteLength) * 50));
              api.ui.progress.setStage('render', false, 'Çizgi/Alan: ' + rendered);
            }
          }
        }
        pos += totalSize;
      } else {
        pos += totalSize;
      }
    }

    if (api.ui?.progress) {
      api.ui.progress.setStage('render', false, 'Çizgiler tamamlandı');
    }

    const prevZoom = NCZViewer._zoomToLayer;
    NCZViewer._zoomToLayer = function (lc) {
      const pts = _bounds[lc] || [];
      if (pts.length === 0) { if (prevZoom) prevZoom(lc); return; }
      NCZViewer.map.closePopup();
      pts.length === 1
        ? NCZViewer.map.setView(pts[0], 18, { animate: true })
        : NCZViewer.map.fitBounds(L.latLngBounds(pts).pad(0.1), { animate: true });
    };

    return rendered;
  }

  NCZViewer.registerModule({
    name: 'lines-renderer',
    init(api) {
      console.log('%c[lines-renderer] v3.0 yüklendi — 4-byte header + gis_difference', 'color:#4ade80;font-weight:bold;font-size:13px');
    },
    onDataCleared() { Object.keys(_bounds).forEach(k => delete _bounds[k]); },
  });

  NCZViewer.events.on('v1:points:parsed', ({ buf, epsg }) => {
    if (!buf) return;
    NCZViewer.ui.loading(true);
    setTimeout(() => {
      try {
        Object.keys(_bounds).forEach(k => delete _bounds[k]);
        const count = parseAndRender(buf, epsg, NCZViewer);
        if (count > 0) {
          NCZViewer.ui.refreshLayerLists();
          NCZViewer.ui.toast(`✓ ${count} geometri yüklendi`, 'ok', 2000);
        }
        if (NCZViewer.ui?.progress) {
          setTimeout(() => {
            NCZViewer.ui.progress.setStage('render', true, 'Tamamlandı');
            NCZViewer.ui.progress.setPct(100);
            setTimeout(() => NCZViewer.ui.progress.hide(), 800);
          }, 500);
        }
      } catch (err) {
        console.error('[lines-renderer] Hata:', err);
      }
      NCZViewer.ui.loading(false);
    }, 60);
  });
})();


/* ─── render/circle.js ─── */
/**
 * NCZ v1 Circle Renderer  v1.2
 * ───────────────────────────────────────────────────────────────
 * Düzeltmeler v1.2:
 *  - Blok header: 4-byte uint32 LE (eskisi 2-byte → büyük dosyalarda yanlış)
 *  - Tip 22 (0x16) blok desteği eklendi (eskisi sadece 0x15 arıyordu)
 *  - base = pos+7 kayması kaldırıldı; tüm offsetler pos'tan
 *  - toWGS(N, E) → proj4([E, N]) : Easting önce, Northing sonra
 *  - parseCircle offsetleri referansa göre düzeltildi:
 *      pos+7  → layer_code
 *      pos+8  → raw_x / Northing (float64)
 *      pos+16 → raw_y / Easting  (float64)
 *      pos+24 → z (float32)
 *      pos+50 → x2 (float64)  ← çap hesabı
 *      pos+66 → x3 (float64)  ← çap hesabı
 *      radius = abs(x2 - x3) / 2
 */

(function () {
  'use strict';

  // ── proj4 dönüşümü ─────────────────────────────────────────────────
  // proj4([Easting, Northing]) → [lon, lat]
  function toWGS(northing, easting, epsg) {
    try {
      const [lon, lat] = proj4('EPSG:' + epsg, 'EPSG:4326', [easting, northing]);
      return isFinite(lat) && isFinite(lon) ? [lat, lon] : null;
    } catch (_) { return null; }
  }

  function isValidUTM(n, e) {
    return Number.isFinite(n) && Number.isFinite(e) &&
      n > 3_000_000 && n < 6_000_000 &&
      e >   100_000 && e <   900_000;
  }

  // ── Blok header (referans format) ──────────────────────────────────
  // block_type : a[pos]
  // block_size : uint32LE(pos+1) + 4
  // total_size : block_size + 1
  // geometry_type : a[pos+6]
  // Geçerli geometri bloğu: block_type === 21 (0x15) veya 22 (0x16)

  function readBlockSize(a, pos) {
    return (a[pos+1] | a[pos+2]<<8 | a[pos+3]<<16 | a[pos+4]<<24) + 4;
  }

  function isGeomBlock(a, pos) {
    return a[pos] === 21 || a[pos] === 22;
  }

  function gisOffset(a, pos) {
    return a[pos] === 22 ? 28 : 0;
  }

  function layerInfoFor(api, groups, lc, name) {
    if (!groups[lc]) {
      let layerInfo = api.layers.get(lc);
      if (!layerInfo) {
        const grp = L.layerGroup().addTo(api.map);
        layerInfo = api.layers.register(lc, name || `LC_${lc}`, grp);
      }
      groups[lc] = layerInfo;
    }
    return groups[lc];
  }

  // ── GT=3 Circle parser ─────────────────────────────────────────────
  //
  // Referans offsetler (pos'tan):
  //   pos+7  → layer_code (1 byte)
  //   pos+8  → raw_x / Northing (float64)
  //   pos+16 → raw_y / Easting  (float64)
  //   pos+24 → z (float32)
  //   pos+50 → x2 (float64) ← çap için
  //   pos+66 → x3 (float64) ← çap için
  //   radius = abs(x2 - x3) / 2

  function parseCircle(v, a, pos, lt) {
    const lc = a[pos + 7];
    const nx = v.getFloat64(pos + 8,  true);   // Northing
    const ey = v.getFloat64(pos + 16, true);   // Easting
    if (!isValidUTM(nx, ey)) return null;

    const z = v.getFloat32(pos + 24, true);

    const x2 = v.getFloat64(pos + 50, true);
    const x3 = v.getFloat64(pos + 66, true);
    const rad = Math.abs(x2 - x3) / 2;

    if (!Number.isFinite(rad) || rad <= 0 || rad > 100000) return null;

    return {
      type: 'Daire', gt: 3, lc,
      layerName: lt[lc] || `LC_${lc}`,
      N: nx, E: ey, Z: z, rad,
    };
  }

  function makePopup(obj, epsg) {
    const copyStr = `Y: ${obj.N.toFixed(3)}, X: ${obj.E.toFixed(3)} (EPSG:${epsg})`;
    const copyB64 = btoa(unescape(encodeURIComponent(copyStr)));

    const rows = [
      ['Katman',   obj.layerName],
      ['Geometri', obj.type],
      ['Merkez Y', obj.N.toFixed(3)],
      ['Merkez X', obj.E.toFixed(3)],
      ['Yarıçap',  `${obj.rad.toFixed(3)} m`],
      ['Alan',     `${(Math.PI * obj.rad * obj.rad).toFixed(2)} m²`],
    ];

    const tbl = rows.map(r => `<tr><td>${r[0]}</td><td>${r[1]}</td></tr>`).join('');
    return `<div>
      <div class="pop-hd">Öznitelikler</div>
      <table class="pop-tbl"><tbody>${tbl}</tbody></table>
      <div class="pop-actions">
        <button class="pop-btn" title="Tüm katmanı göster"
          onclick="NCZViewer._zoomToLayer(${obj.lc})">🔍</button>
        <button class="pop-btn" title="Y/X kopyala"
          onclick="NCZViewer._copyB64(this,'${copyB64}')">📋</button>
      </div>
    </div>`;
  }

  const _bounds = {};

  function renderObject(obj, epsg, api, groups) {
    const layerInfo = layerInfoFor(api, groups, obj.lc, obj.layerName);
    const col = layerInfo.color;

    const centerLl = toWGS(obj.N, obj.E, epsg);
    if (!centerLl) return false;

    // Çember çevresi (144 segment, kırıksız görünüm)
    const latlngs = [];
    const segments = 144;
    for (let i = 0; i <= segments; i++) {
      const ang = (i / segments) * Math.PI * 2;
      const n = obj.N + obj.rad * Math.sin(ang);
      const e = obj.E + obj.rad * Math.cos(ang);
      const ll = toWGS(n, e, epsg);
      if (ll) latlngs.push(ll);
    }

    if (!_bounds[obj.lc]) _bounds[obj.lc] = [];
    _bounds[obj.lc].push(centerLl);

    const circle = L.polygon(latlngs, {
      color:        col,
      weight:       2,
      opacity:      0.9,
      fillColor:    col,
      fillOpacity:  0.12,
      smoothFactor: 0,
      noClip:       true,
    });

    circle.on('click', ev => {
      L.popup({ maxWidth: 300 })
        .setLatLng(ev.latlng)
        .setContent(makePopup(obj, epsg))
        .openOn(api.map);
    });
    layerInfo.group.addLayer(circle);
    return true;
  }

  function parseAndRender(buf, epsg, api) {
    const v  = new DataView(buf);
    const a  = new Uint8Array(buf);
    const lt = window.NCZParserV1
      ? NCZParserV1.readLayerTable(buf, NCZParserV1.resolveConfig(
          NCZParserV1.detectVersion(buf).formatKey).layerTable)
      : {};
    const groups = {};
    let rendered = 0;
    let pos = 0;

    while (pos + 5 < buf.byteLength) {
      const bt        = a[pos];
      const blockSize = readBlockSize(a, pos);
      const totalSize = blockSize + 1;

      // Geçersiz blok → 1 byte atla
      if (blockSize < 4 || pos + totalSize > buf.byteLength) { pos++; continue; }

      if (bt === 21 || bt === 22) {
        if (blockSize >= 7 && a[pos + 6] === 3) {
          let obj = null;
          try { obj = parseCircle(v, a, pos, lt); } catch (_) {}
          if (obj && renderObject(obj, epsg, api, groups)) {
            rendered++;
            if (api.ui?.progress && rendered % 50 === 0) {
              api.ui.progress.updateStats(api.ui.progress._geom + 50, undefined);
            }
          }
        }
        pos += totalSize;
      } else {
        pos += totalSize;
      }
    }

    // _zoomToLayer zinciri
    const prevZoom = NCZViewer._zoomToLayer;
    NCZViewer._zoomToLayer = function (lc) {
      const pts = _bounds[lc] || [];
      if (pts.length === 0) { if (prevZoom) prevZoom(lc); return; }
      NCZViewer.map.closePopup();
      pts.length === 1
        ? NCZViewer.map.setView(pts[0], 18, { animate: true })
        : NCZViewer.map.fitBounds(L.latLngBounds(pts).pad(0.1), { animate: true });
    };

    return rendered;
  }

  NCZViewer.registerModule({
    name: 'circle-renderer',
    init(api) { console.log('[circle-renderer] v1.2 yüklendi — GT=3 daire render'); },
    onDataCleared() { Object.keys(_bounds).forEach(k => delete _bounds[k]); },
  });

  NCZViewer.events.on('v1:points:parsed', ({ buf, epsg }) => {
    if (!buf) return;
    setTimeout(() => {
      try {
        Object.keys(_bounds).forEach(k => delete _bounds[k]);
        const count = parseAndRender(buf, epsg, NCZViewer);
        if (count > 0) {
          NCZViewer.ui.refreshLayerLists();
          NCZViewer.ui.toast(`✓ ${count} daire yüklendi`, 'ok', 2000);
        }
        if (NCZViewer.ui?.progress) {
          setTimeout(() => {
            NCZViewer.ui.progress.setStage('render', true, 'Tamamlandı');
            NCZViewer.ui.progress.setPct(100);
            setTimeout(() => NCZViewer.ui.progress.hide(), 800);
          }, 500);
        }
      } catch (err) {
        console.error('[circle-renderer] Hata:', err);
      }
    }, 80);
  });
})();


/* ─── loader/geojson-loader.js ─── */
/**
 * NCZ Viewer — GeoJSON Yükleyici Modülü  v1.0
 * ══════════════════════════════════════════════════════════════════════
 *
 * Desteklenen geometriler:
 *   Point, MultiPoint, LineString, MultiLineString,
 *   Polygon, MultiPolygon, GeometryCollection, Feature, FeatureCollection
 *
 * Katman ayırma:
 *   Her feature'ın properties.layer → properties.name → properties.id
 *   → dosya adı (fallback) alanına göre katman belirlenir.
 *   Aynı katman adındaki feature'lar tek Leaflet LayerGroup'a eklenir.
 *
 * Koordinat sistemi:
 *   GeoJSON standardı: WGS84 [lon, lat] — proj4 dönüşümü gerekmez.
 *
 * Popup:
 *   Feature.properties'deki tüm alanlar tablo olarak gösterilir.
 *   Boş/null değerler gizlenir.
 *
 * ══════════════════════════════════════════════════════════════════════
 */

(function () {
  'use strict';

  // ── Renk paleti (NCZ ile aynı) ────────────────────────────────
  const PAL = [
    '#60a5fa','#4ade80','#fbbf24','#f87171','#a78bfa',
    '#06b6d4','#f472b6','#fb923c','#34d399','#a3e635',
    '#e879f9','#2dd4bf','#f43f5e','#818cf8',
  ];
  let _palIdx = 0;
  const _layerColors = {};

  function layerColor(name) {
    if (!_layerColors[name]) {
      _layerColors[name] = PAL[_palIdx % PAL.length];
      _palIdx++;
    }
    return _layerColors[name];
  }

  // ── Feature'dan katman adı çıkar ─────────────────────────────
  function resolveLayerName(feature, fallback) {
    const p = feature.properties || {};
    return (p.layer || p.Layer || p.LAYER ||
            p.name  || p.Name  || p.NAME  ||
            p.id    || p.ID    || fallback || 'GeoJSON').toString().trim();
  }

  // ── Popup HTML ────────────────────────────────────────────────
  function makePopup(feature, layerName) {
    const p = feature.properties || {};
    const keys = Object.keys(p).filter(k => p[k] !== null && p[k] !== undefined && p[k] !== '');

    const rows = keys.map(k =>
      `<tr><td>${escHtml(k)}</td><td>${escHtml(String(p[k]))}</td></tr>`
    ).join('');

    const geomType = feature.geometry ? feature.geometry.type : '—';
    const headerRows = `
      <tr><td>Katman</td><td>${escHtml(layerName)}</td></tr>
      <tr><td>Geometri</td><td>${geomType}</td></tr>
    `;

    return `<div>
      <div class="pop-hd">Öznitelikler</div>
      <table class="pop-tbl"><tbody>${headerRows}${rows}</tbody></table>
    </div>`;
  }

  function escHtml(s) {
    return String(s).replace(/[<>&"]/g, c =>
      ({ '<':'&lt;', '>':'&gt;', '&':'&amp;', '"':'&quot;' }[c])
    );
  }

  // ── Leaflet geometry oluştur ──────────────────────────────────
  function geomToLeaflet(geometry, color) {
    if (!geometry) return null;
    const t = geometry.type;
    const c = geometry.coordinates;
    const style = { color, fillColor: color, weight: 2, opacity: 0.9, fillOpacity: 0.15 };
    const ptOpt = { radius: 5, color, fillColor: color, fillOpacity: 0.85, weight: 1.5 };

    try {
      if (t === 'Point') {
        return L.circleMarker([c[1], c[0]], ptOpt);
      }
      if (t === 'MultiPoint') {
        const grp = L.layerGroup();
        c.forEach(pt => grp.addLayer(L.circleMarker([pt[1], pt[0]], ptOpt)));
        return grp;
      }
      if (t === 'LineString') {
        return L.polyline(c.map(p => [p[1], p[0]]), style);
      }
      if (t === 'MultiLineString') {
        return L.polyline(c.map(ring => ring.map(p => [p[1], p[0]])), style);
      }
      if (t === 'Polygon') {
        return L.polygon(c.map(ring => ring.map(p => [p[1], p[0]])), style);
      }
      if (t === 'MultiPolygon') {
        return L.polygon(c.map(poly => poly.map(ring => ring.map(p => [p[1], p[0]]))), style);
      }
      if (t === 'GeometryCollection') {
        const grp = L.layerGroup();
        (geometry.geometries || []).forEach(g => {
          const ly = geomToLeaflet(g, color);
          if (ly) grp.addLayer(ly);
        });
        return grp;
      }
    } catch (err) {
      console.warn('[geojson-loader] Geometri hatası:', t, err);
    }
    return null;
  }

  // ── Feature listesini düzleştir ───────────────────────────────
  function flattenFeatures(geojson) {
    const features = [];
    function walk(obj) {
      if (!obj) return;
      if (obj.type === 'FeatureCollection') {
        (obj.features || []).forEach(walk);
      } else if (obj.type === 'Feature') {
        features.push(obj);
      } else if (obj.type && obj.coordinates !== undefined) {
        // Naked geometry
        features.push({ type: 'Feature', geometry: obj, properties: {} });
      }
    }
    walk(geojson);
    return features;
  }

  // ── Ana yükleyici ─────────────────────────────────────────────
  function loadGeoJSON(geojson, filename, api) {
    _palIdx = 0;
    Object.keys(_layerColors).forEach(k => delete _layerColors[k]);

    const features = flattenFeatures(geojson);
    if (features.length === 0) {
      api.ui.toast('GeoJSON içinde feature bulunamadı', 'err', 3000);
      api.ui.loading(false);
      return;
    }

    const baseName = filename.replace(/\.[^/.]+$/, '');

    // Feature'ları katmanlara grupla
    const byLayer = {};
    features.forEach(f => {
      const lname = resolveLayerName(f, baseName);
      if (!byLayer[lname]) byLayer[lname] = [];
      byLayer[lname].push(f);
    });

    let totalRendered = 0;
    let lcCounter = 9000; // GeoJSON katmanları için LC aralığı

    for (const [lname, feats] of Object.entries(byLayer)) {
      const lc    = lcCounter++;
      const color = layerColor(lname);
      const group = L.layerGroup().addTo(api.map);
      api.layers.register(lc, lname, group);

      // Rengi hemen override et (register PAL'dan atar, bizimkini override et)
      const info = api.layers.get(lc);
      if (info) info.color = color;

      feats.forEach(f => {
        const shape = geomToLeaflet(f.geometry, color);
        if (!shape) return;

        const popupHtml = makePopup(f, lname);

        if (shape instanceof L.LayerGroup) {
          // MultiPoint / GeometryCollection → her alt katmana popup
          shape.eachLayer(sub => {
            if (sub.bindPopup) sub.bindPopup(popupHtml, { maxWidth: 320 });
          });
        } else {
          shape.on('click', ev => {
            L.popup({ maxWidth: 320 })
              .setLatLng(ev.latlng || (shape.getLatLng ? shape.getLatLng() : ev.latlng))
              .setContent(popupHtml)
              .openOn(api.map);
          });
        }

        group.addLayer(shape);
        totalRendered++;
      });

      console.log(`[geojson-loader] ${lname} (LC=${lc}): ${feats.length} feature`);
    }

    const layerCount = Object.keys(byLayer).length;

    api.ui.updateStats(
      totalRendered.toLocaleString('tr'),
      layerCount,
      filename,
      'EPSG:4326'
    );
    api.ui.showLayerUI();
    api.ui.refreshLayerLists();
    api.ui.loading(false);
    api.ui.toast(`✓ ${totalRendered.toLocaleString('tr')} feature · ${layerCount} katman`, 'ok', 2500);

    console.log(`[geojson-loader] Toplam ${totalRendered} feature, ${layerCount} katman`);
  }

  // ── Modül kaydı ───────────────────────────────────────────────
  NCZViewer.registerModule({
    name: 'geojson-loader',

    init(api) {
      console.log('[geojson-loader] v1.0 yüklendi — Point, Line, Polygon, Multi*, GeometryCollection');

      api.events.on('geojson:loaded', ({ geojson, filename }) => {
        api.ui.loading(true);
        setTimeout(() => {
          try {
            loadGeoJSON(geojson, filename, api);
          } catch (err) {
            console.error('[geojson-loader] Hata:', err);
            api.ui.toast('GeoJSON render hatası: ' + err.message, 'err', 5000);
            api.ui.loading(false);
          }
        }, 30);
      });

      api.events.on('data:cleared', () => {
        _palIdx = 0;
        Object.keys(_layerColors).forEach(k => delete _layerColors[k]);
      });
    },
  });

})();


/* ─── ui/label-toggle.js ─── */
/**
 * Nokta İsimleri Kontrol Modülü (v1.1)
 * ─────────────────────────────────────
 * - Standart olarak KAPALI başlar.
 * - İkon bir nokta ve etiketi temsil eder.
 */

(function () {
  'use strict';

  NCZViewer.registerModule({
    name: 'label-toggle',

    init(api) {
      // 1. Durum Takibi (Varsayılan: Kapalı)
      let showLabels = false;
      const styleId = 'ncz-hide-labels-style';
      
      // 2. Varsayılan olarak etiketleri gizle (CSS enjekte et)
      const hideStyle = document.createElement('style');
      hideStyle.id = styleId;
      hideStyle.innerHTML = '.ncz-pname { display: none !important; }';
      document.head.appendChild(hideStyle);

      // 3. Topbar Butonu (Nokta ve Etiket İkonu)
      const btnHtml = `
        <button class="ibtn" id="labelToggleBtn" title="Nokta İsimlerini Göster/Gizle" style="color:var(--tx2)">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <circle cx="6" cy="12" r="3" fill="currentColor"></circle>
            <line x1="12" y1="9" x2="20" y2="9"></line>
            <line x1="12" y1="15" x2="18" y2="15"></line>
          </svg>
        </button>
      `;
      
      api.ui.addTopbarBtn(btnHtml);

      // 4. Buton Tıklama Mantığı
      const btn = document.getElementById('labelToggleBtn');
      
      btn.addEventListener('click', function() {
        showLabels = !showLabels;
        
        let styleEl = document.getElementById(styleId);
        
        if (showLabels) {
          // GÖSTER: CSS kuralını kaldır
          if (styleEl) styleEl.remove();
          this.style.color = 'var(--acc2)'; // Aktif (Mavi/Vurgulu) renk
          api.ui.toast('Nokta isimleri açıldı', 'ok', 1500);
        } else {
          // GİZLE: CSS kuralını geri ekle
          if (!styleEl) {
            styleEl = document.createElement('style');
            styleEl.id = styleId;
            styleEl.innerHTML = '.ncz-pname { display: none !important; }';
            document.head.appendChild(styleEl);
          }
          this.style.color = 'var(--tx2)'; // Pasif (Gri) renk
          api.ui.toast('Nokta isimleri kapatıldı', 'info', 1500);
        }
      });

      console.log('[label-toggle] v1.1 yüklendi — nokta isimleri göster/gizle (varsayılan: gizli)');
    }
  });

})();

